NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket packet;
    hexi::reader reader(buffer);

    // Read packet_id
    packet.packet_id = reader.read<uint32_t>();

    // Read username using length prefix
    packet.username = reader.read_prefixed<uint32_t, std::string>();

    // Read score count, then use read_container to read scores vector
    uint32_t score_count = reader.read<uint32_t>();
    packet.scores = reader.read_container<uint32_t>(score_count);

    // Read metadata string as null-terminated for zero-copy
    packet.metadata = reader.read_null_terminated<std::string>();

    // Skip any remaining padding bytes (if any)
    if (reader.remaining() > 0) {
        reader.skip(reader.remaining());
    }

    return packet;
}

