template<size_t buffer_size = 1024>
void write_data_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, const std::vector<uint8_t>& data) {
    // Prepare space in the buffer for writing
    auto writable = buffer.prepare(data.size());

    // Copy data to the buffer
    std::byte* dest = static_cast<std::byte*>(writable.data());
    for (size_t i = 0; i < data.size(); ++i) {
        dest[i] = static_cast<std::byte>(data[i]);
    }

    // Commit the written data
    buffer.commit(data.size());
}

