# Complete Implementation

```cpp
#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

using namespace hexi::detail;

bool check_regions_overlap(const void* src, std::size_t src_len, const void* dst, std::size_t dst_len) {
    // Empty regions or null pointers don't overlap
    if (src == nullptr || dst == nullptr || src_len == 0 || dst_len == 0) {
        return false;
    }

    // Convert to byte pointers for address arithmetic
    const auto* src_start = static_cast<const unsigned char*>(src);
    const auto* src_end = src_start + src_len;
    const auto* dst_start = static_cast<const unsigned char*>(dst);
    const auto* dst_end = dst_start + dst_len;

    // Two regions overlap if: src_start < dst_end AND dst_start < src_end
    // This checks if either region starts before the other ends
    return src_start < dst_end && dst_start < src_end;
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    // Validate pointers
    if (destination == nullptr || source == nullptr) {
        return false;
    }

    // Nothing to copy - still considered successful
    if (length == 0) {
        return true;
    }

    // Check for overlap between source and destination regions
    if (check_regions_overlap(source, length, destination, length)) {
        // Use memmove for overlapping regions (safe for overlaps)
        std::memmove(destination, source, length);
    } else {
        // Use memcpy for non-overlapping regions (potentially faster)
        std::memcpy(destination, source, length);
    }

    return true;
}
```

